import{_ as l,C as o,o as s,c as n,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Bulgaria Healthcare & HRT","description":"Transgender healthcare access in Bulgaria","frontmatter":{"layout":"doc","title":"Bulgaria Healthcare & HRT","description":"Transgender healthcare access in Bulgaria"},"headers":[],"relativePath":"europe/bulgaria/healthcare.md","filePath":"europe/bulgaria/healthcare.md","lastUpdated":null}'),c={name:"europe/bulgaria/healthcare.md"};function h(g,e,u,p,b,y){const t=o("Badge");return s(),n("div",null,[a(t,{variant:"red"},{default:i(()=>[...e[0]||(e[0]=[r("No Dedicated Gender Clinics",-1)])]),_:1}),a(t,{variant:"red"},{default:i(()=>[...e[1]||(e[1]=[r("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:i(()=>[...e[2]||(e[2]=[r("EU Prescription Portability",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-bulgaria" tabindex="-1">Healthcare &amp; HRT in Bulgaria <a class="header-anchor" href="#healthcare-hrt-in-bulgaria" aria-label="Permalink to &quot;Healthcare &amp; HRT in Bulgaria&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Bulgaria has <strong>extremely limited</strong> transgender healthcare and <strong>no dedicated gender clinics</strong>:</p><ul><li><strong>Psychiatric diagnosis required</strong> to access any trans healthcare</li><li>No specialized transgender health services exist</li><li>Healthcare providers have very little experience with trans patients</li><li>Almost all services are concentrated in <strong>Sofia</strong></li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-psychiatric-assessment" tabindex="-1">Step 1: Psychiatric Assessment <a class="header-anchor" href="#step-1-psychiatric-assessment" aria-label="Permalink to &quot;Step 1: Psychiatric Assessment&quot;">​</a></h3><ul><li>Contact a psychiatrist (public or private) in Sofia</li><li>Very few psychiatrists specialize in or have experience with gender dysphoria</li><li>Multiple sessions typically required over several months</li><li>Diagnosis per ICD-10/11</li></ul><h3 id="step-2-endocrinology" tabindex="-1">Step 2: Endocrinology <a class="header-anchor" href="#step-2-endocrinology" aria-label="Permalink to &quot;Step 2: Endocrinology&quot;">​</a></h3><ul><li>No dedicated trans endocrinology services</li><li>General endocrinologists may prescribe HRT with a psychiatric referral</li><li>Most endocrinologists have little to no experience with trans patients</li><li>You may need to educate your provider about treatment protocols</li></ul><h3 id="step-3-ongoing-care" tabindex="-1">Step 3: Ongoing Care <a class="header-anchor" href="#step-3-ongoing-care" aria-label="Permalink to &quot;Step 3: Ongoing Care&quot;">​</a></h3><ul><li>HRT monitoring by endocrinologist</li><li>Follow-up visits every 3-6 months</li><li>Blood tests at general laboratories</li><li>Medication availability can be inconsistent</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>University Hospital Alexandrovska</td><td>Sofia</td><td>Psychiatry, endocrinology (limited trans experience)</td></tr><tr><td>Military Medical Academy</td><td>Sofia</td><td>Psychiatry referrals</td></tr><tr><td>Private psychiatrists</td><td>Sofia, Plovdiv</td><td>Assessment (shorter wait times)</td></tr><tr><td>Private endocrinologists</td><td>Sofia</td><td>HRT (very limited trans experience)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Bulgaria under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Bulgarian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Stock issues</strong>: Some HRT medications may require special ordering</li><li><strong>Pharmacies</strong>: Major chains (Sopharmacy, VChele) in larger cities</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Bulgaria</li><li>All surgeries require travel abroad</li><li>No public funding for gender-affirming surgery</li><li>No established referral pathways for surgery abroad</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Bulgarian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€50-100</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€50-80</td></tr><tr><td>HRT (monthly)</td><td>€15-40</td><td>€20-50</td></tr><tr><td>Private psychiatrist</td><td>€30-60</td><td>€40-80</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.mh.government.bg/" target="_blank" rel="noreferrer">Bulgarian Ministry of Health</a></li><li><a href="https://www.bghelsinki.org/" target="_blank" rel="noreferrer">Bulgarian Helsinki Committee</a></li><li><a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ILGA-Europe - Healthcare Report</a></li></ul>',21))])}const v=l(c,[["render",h]]);export{f as __pageData,v as default};
